validateStock: async () => {
  const { items } = get();
  const stockPromises = items.map(item => fetch(`/api/products/${item.id}/stock`).then(res => res.json()));
  const stocks = await Promise.all(stockPromises);
  const errors = items.filter((item, idx) => item.quantity > stocks[idx].available);
  set({ stockErrors: errors });
  return errors.length === 0;
}
```

